commands.cmd:
ids=$(docker ps -aq --filter name=hlc-) || { echo "docker ps failed" >&2; exit 1; }
if [ -z "$ids" ]; then
  printf '{"results":[]}'
else
  inspect_out=$(printf '%s\n' "$ids" | xargs docker inspect) || { echo "docker inspect failed" >&2; exit 1; }
  printf '%s' "$inspect_out" | jq -c '{
    results: map({
      name: (.Name | ltrimstr("/")),
      restart_count: .RestartCount,
      state: .State.Status,
      health: (.State.Health.Status // "none")
    })
  }' || { echo "jq failed" >&2; exit 1; }
fi
